import{S as n,l as a}from"./chunk-SIZXVJZC.js";var s=[{id:1,title:"Low Flow Monitoring for Eel Pass",slug:"low-flow-monitoring-eel-pass",category:"News",date:"14 May 2026",coverImage:"assets/news-page/Article Image.svg",galleryImages:["assets/news-page/20230627_120623 2.svg","assets/news-page/20230627_120623 2.svg","assets/news-page/20230627_120623 2.svg"],sections:[{subtitle:"DFM 6.1 Doppler Flow Meter Provides Flow Confirmation for Eel Pass in the United Kingdom",paragraphs:["The DFM 6.1 Doppler flow meter has been deployed successfully at an eel pass facility in the United Kingdom, providing reliable low-flow measurement and confirmation in a particularly challenging monitoring environment.","Eel passes are specially designed infrastructure elements that allow European eels to migrate upstream past weirs, dams, and other obstacles in waterways. Accurate flow monitoring at these structures is critical to ensure adequate water volumes are maintained throughout the migration season, supporting both regulatory compliance and ecological conservation goals."]},{subtitle:"Clamp-on Doppler Flow Proven Reliable",paragraphs:["The clamp-on design of the DFM 6.1 enabled rapid, non-invasive installation without interrupting water flow or disturbing the sensitive eel pass environment. The sensor attaches directly to the exterior of the pipe, eliminating the need for pipe cutting, welding, or extended system downtime.","Field performance data confirmed that the instrument maintained stable, accurate readings across the full range of expected flow velocities \u2014 from very low flows typical of dry weather periods to higher flows associated with rainfall and elevated river levels.","This installation demonstrates the versatility and operational reliability of Giga Systems' clamp-on measurement technology in real-world environmental monitoring applications, reinforcing our commitment to delivering innovative and precise solutions for complex field measurement challenges."]}]},{id:2,title:"Giga Systems Launches Next-Gen Water PurificationTechnology",slug:"giga-systems-launches-water-purification",category:"News",date:"10 May 2026",coverImage:"assets/news-page/Article-Image2.svg",sections:[{paragraphs:["Giga Systems is proud to announce the launch of a new generation of water purification and quality monitoring technology, bringing advanced environmental measurement capabilities to clients across Egypt, the Middle East, and Africa.","The new system incorporates real-time sensor arrays, IoT connectivity, and cloud-based data management to deliver comprehensive water quality insights that support informed decision-making for both government and private sector clients."]}]},{id:3,title:"Giga Systems Launches Next-Gen Water PurificationTechnology",slug:"partnership-environmental-monitoring",category:"Articles",date:"05 May 2026",coverImage:"assets/news-page/Article-Image3.svg",sections:[{paragraphs:["Giga Systems has formalized a series of strategic partnerships with leading global manufacturers of environmental monitoring and laboratory instrumentation equipment, reinforcing its role as the preferred regional solutions provider across diverse industries.","These alliances grant Giga Systems exclusive authorized distributorship rights for a range of advanced measurement technologies, ensuring customers receive best-in-class products supported by full technical training, after-sales service, and calibration capabilities."]}]},{id:4,title:"Giga Systems Launches Next-Gen Water PurificationTechnology",slug:"iot-integration-water-quality",category:"Articles",date:"28 Apr 2026",coverImage:"assets/news-page/Article-Image4.svg",sections:[{paragraphs:["The integration of Internet of Things technology into water quality monitoring systems represents one of the most significant advances in environmental measurement of the past decade. By connecting sensors, data loggers, and cloud platforms, organizations can now access real-time water quality data from anywhere in the world.","Giga Systems has been at the forefront of implementing IoT-enabled monitoring networks, delivering complete system solutions that combine industry-leading sensors with robust telemetry infrastructure and intuitive data visualization dashboards."]}]}],r=class e{getArticles(){return a(s)}getArticleBySlug(i){return a(s.find(t=>t.slug===i))}static \u0275fac=function(t){return new(t||e)};static \u0275prov=n({token:e,factory:e.\u0275fac,providedIn:"root"})};export{r as a};
